// Process and validate the AI response
const aiResponse = $json.output;
const originalInput = $('Input Processor').item.json;

try {
  // Try to parse JSON response
  let contentData;
  if (typeof aiResponse === 'string') {
    // Remove any markdown code block markers
    const cleanResponse = aiResponse.replace(/```json\n?|```\n?/g, '').trim();
    contentData = JSON.parse(cleanResponse);
  } else {
    contentData = aiResponse;
  }

  // Validate required fields
  const title = contentData.title || 'Enhanced Video Content';
  const visualPrompt = contentData.visual_prompt || contentData.visualPrompt || 'A modern, engaging video with dynamic visuals and vibrant colors';

  // Ensure title is within character limit
  const truncatedTitle = title.length > 60 ? title.substring(0, 57) + '...' : title;

  return {
    json: {
      success: true,
      chat_id: originalInput.chat_id,
      url: originalInput.url,
      platform: originalInput.platform,
      context: originalInput.context,
      title: truncatedTitle,
      visual_prompt: visualPrompt,
      character_count: truncatedTitle.length,
      message: `✅ Content enhanced successfully!\n\n🎬 Title: "${truncatedTitle}"\n🎨 Visual concept generated!`
    }
  };
} catch (error) {
  // Fallback if JSON parsing fails
  return {
    json: {
      success: false,
      chat_id: originalInput.chat_id,
      url: originalInput.url,
      platform: originalInput.platform,
      error: 'Failed to parse AI response',
      title: 'Enhanced Video Content',
      visual_prompt: 'A modern, dynamic video with engaging visuals, vibrant colors, and smooth transitions that capture viewer attention',
      message: '⚠️ Used fallback content enhancement. Title and visuals generated with default settings.'
    }
  };
}
